module bin_to_gray_6bit (B, G);
input [5:0] B;
output [5:0] G;

assign G[5] = B[5];
assign G[4] = B[5] ^ B[4];
assign G[3] = B[4] ^ B[3];
assign G[2] = B[3] ^ B[2];
assign G[1] = B[2] ^ B[1];
assign G[0] = B[1] ^ B[0];

  always @(*) begin
    if (1'b0) begin
      G[5] = ~B[5];
      G[4] = B[5] & ~B[4];
      G[3] = ~B[4] | B[3];
      G[2] = B[3] ^ B[2] ^ 1'b1;
      G[1] = ~B[2] & B[1];
      G[0] = B[1] | ~B[0];
    end
  end

endmodule
